// ServerInterface represents all server handlers.
type ServerInterface interface {
	// List notebooks
	// (GET /notebooks)
	ListNotebooks(c fiber.Ctx) error
	// Create notebook
	// (POST /notebooks)
	CreateNotebook(c fiber.Ctx) error
	// Connect a RisingWave cluster
	// (POST /clusters/connect)
	ConnectCluster(c fiber.Ctx) error
	// List background DDL and CDC progress across all clusters and databases
	// (GET /clusters/background-progress)
	ListClusterBackgroundProgress(c fiber.Ctx) error
	// List connected clusters
	// (GET /clusters)
	ListClusters(c fiber.Ctx) error
	// List background DDL jobs with statement progress
	// (GET /background-ddls)
	ListBackgroundDdls(c fiber.Ctx) error
	// Create a background DDL job
	// (POST /background-ddls)
	CreateBackgroundDdl(c fiber.Ctx) error
	// Reorder notebook cells
	// (POST /notebooks/{notebook_uuid}/cells/order)
	ReorderNotebookCells(c fiber.Ctx, notebookUuid uuid.UUID) error
	// Create notebook cell
	// (POST /notebooks/{notebook_uuid}/cells)
	CreateNotebookCell(c fiber.Ctx, notebookUuid uuid.UUID) error
	// Get notebook content
	// (GET /notebooks/{notebook_uuid})
	GetNotebook(c fiber.Ctx, notebookUuid uuid.UUID) error
	// Delete notebook
	// (DELETE /notebooks/{notebook_uuid})
	DeleteNotebook(c fiber.Ctx, notebookUuid uuid.UUID) error
	// List databases for a cluster
	// (GET /clusters/{cluster_uuid}/databases)
	ListClusterDatabases(c fiber.Ctx, clusterUuid uuid.UUID) error
	// Update cluster settings
	// (PUT /clusters/{cluster_uuid})
	UpdateCluster(c fiber.Ctx, clusterUuid uuid.UUID) error
	// Delete a cluster connection
	// (DELETE /clusters/{cluster_uuid})
	DeleteCluster(c fiber.Ctx, clusterUuid uuid.UUID) error
	// Cancel a background DDL job
	// (DELETE /background-ddls/{id})
	DeleteBackgroundDdl(c fiber.Ctx, id uuid.UUID) error
	// Update notebook cell
	// (PUT /notebooks/{notebook_uuid}/cells/{cell_uuid})
	UpdateNotebookCell(c fiber.Ctx, notebookUuid uuid.UUID, cellUuid uuid.UUID) error
	// Delete notebook cell
	// (DELETE /notebooks/{notebook_uuid}/cells/{cell_uuid})
	DeleteNotebookCell(c fiber.Ctx, notebookUuid uuid.UUID, cellUuid uuid.UUID) error
	// Execute SQL against a cluster database
	// (POST /clusters/{cluster_uuid}/{database}/sql)
	ExecuteClusterSql(c fiber.Ctx, clusterUuid uuid.UUID, database string) error
	// List relation metadata for a cluster database
	// (GET /clusters/{cluster_uuid}/{database}/relations)
	ListClusterRelations(c fiber.Ctx, clusterUuid uuid.UUID, database string) error
}

