// FiberServerOptions provides options for the Fiber server.
type FiberServerOptions struct {
	BaseURL     string
	Middlewares []MiddlewareFunc
}

// RegisterHandlers creates http.Handler with routing matching OpenAPI spec.
func RegisterHandlers(router fiber.Router, si ServerInterface) {
	RegisterHandlersWithOptions(router, si, FiberServerOptions{})
}

// RegisterHandlersWithOptions creates http.Handler with additional options
func RegisterHandlersWithOptions(router fiber.Router, si ServerInterface, options FiberServerOptions) {
	wrapper := ServerInterfaceWrapper{Handler: si}

	for _, m := range options.Middlewares {
		router.Use(fiber.Handler(m))
	}

	router.Get(options.BaseURL+"/notebooks", wrapper.ListNotebooks)

	router.Post(options.BaseURL+"/notebooks", wrapper.CreateNotebook)

	router.Post(options.BaseURL+"/clusters/connect", wrapper.ConnectCluster)

	router.Get(options.BaseURL+"/clusters/background-progress", wrapper.ListClusterBackgroundProgress)

	router.Get(options.BaseURL+"/clusters", wrapper.ListClusters)

	router.Get(options.BaseURL+"/background-ddls", wrapper.ListBackgroundDdls)

	router.Post(options.BaseURL+"/background-ddls", wrapper.CreateBackgroundDdl)

	router.Post(options.BaseURL+"/notebooks/:notebook_uuid/cells/order", wrapper.ReorderNotebookCells)

	router.Post(options.BaseURL+"/notebooks/:notebook_uuid/cells", wrapper.CreateNotebookCell)

	router.Get(options.BaseURL+"/notebooks/:notebook_uuid", wrapper.GetNotebook)

	router.Delete(options.BaseURL+"/notebooks/:notebook_uuid", wrapper.DeleteNotebook)

	router.Get(options.BaseURL+"/clusters/:cluster_uuid/databases", wrapper.ListClusterDatabases)

	router.Put(options.BaseURL+"/clusters/:cluster_uuid", wrapper.UpdateCluster)

	router.Delete(options.BaseURL+"/clusters/:cluster_uuid", wrapper.DeleteCluster)

	router.Delete(options.BaseURL+"/background-ddls/:id", wrapper.DeleteBackgroundDdl)

	router.Put(options.BaseURL+"/notebooks/:notebook_uuid/cells/:cell_uuid", wrapper.UpdateNotebookCell)

	router.Delete(options.BaseURL+"/notebooks/:notebook_uuid/cells/:cell_uuid", wrapper.DeleteNotebookCell)

	router.Post(options.BaseURL+"/clusters/:cluster_uuid/:database/sql", wrapper.ExecuteClusterSql)

	router.Get(options.BaseURL+"/clusters/:cluster_uuid/:database/relations", wrapper.ListClusterRelations)

}

type Validator interface {
	// AuthFunc is called before the request is processed. The response will be 401 if the auth fails.
	AuthFunc(fiber.Ctx) error

	// PreValidate is called before the request is processed. The response will be 403 if the validation fails.
	PreValidate(fiber.Ctx) error

	// PostValidate is called after the request is processed. The response will be 403 if the validation fails.
	PostValidate(fiber.Ctx) error
}

type XMiddleware struct {
	ServerInterface
	Validator
}

func NewXMiddleware(handler ServerInterface, validator Validator) ServerInterface {
	return &XMiddleware{ServerInterface: handler, Validator: validator}
}
